steps.script:
const cleanArg = (v) => { const t = String(v == null ? '' : v).trim(); return /^\{[a-zA-Z0-9_]+\}$/.test(t) ? '' : t; };
const term = cleanArg('{term}');
const country = (cleanArg('{country}') || 'us').toLowerCase();
const target = `https://apps.apple.com/${encodeURIComponent(country)}/iphone/search?term=${encodeURIComponent(term)}`;
setTimeout(() => window.location.assign(target), 0);
return { redirected: true, target, country };
